@namespace Lumeo
@implements IDisposable
@inject Lumeo.Services.IOverlayService Overlay
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@*
    ConfirmButton — a Button that opens an AlertDialog before firing OnConfirm.

    Replaces the ~15-line boilerplate of wiring a Button + AlertDialog manually
    for the destructive-action / commit-changes flow. Internally delegates to
    OverlayService.ShowAlertDialogAsync, so the dialog renders through the
    existing OverlayProvider — no extra DOM in the consumer's tree.

    The button itself accepts the same Variant / Size / Disabled / IsLoading
    parameters as <Button>, so it composes pixel-for-pixel with surrounding
    buttons.
*@

<Button Variant="@Variant"
        Size="@Size"
        Disabled="@Disabled"
        IsLoading="@IsLoading"
        Class="@Class"
        OnClick="HandleClick"
        @attributes="AdditionalAttributes">
    @ChildContent
</Button>

@code {
    /// <summary>Button content (the visible label or icon).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Title shown at the top of the confirm dialog.
    /// Defaults to the AlertDialog default ("Are you sure?").</summary>
    [Parameter] public string? Title { get; set; }

    /// <summary>Optional descriptive body text under the title.</summary>
    [Parameter] public string? Description { get; set; }

    /// <summary>Label for the confirm action button. Defaults to "Continue".</summary>
    [Parameter] public string? ConfirmText { get; set; }

    /// <summary>Label for the cancel action button. Defaults to "Cancel".</summary>
    [Parameter] public string? CancelText { get; set; }

    /// <summary>When true, the confirm button is styled as destructive
    /// (red) — for delete / remove / discard actions.</summary>
    [Parameter] public bool IsDestructive { get; set; }

    /// <summary>Fires after the user confirms. Does NOT fire on cancel —
    /// listen to <see cref="OnCancel"/> for that path if needed.</summary>
    [Parameter] public EventCallback OnConfirm { get; set; }

    /// <summary>Fires when the user cancels (or closes the dialog without
    /// confirming). Optional — most consumers only care about OnConfirm.</summary>
    [Parameter] public EventCallback OnCancel { get; set; }

    /// <summary>Visual variant of the trigger button. Defaults to
    /// <see cref="Button.ButtonVariant.Default"/>; commonly set to
    /// <see cref="Button.ButtonVariant.Destructive"/> for delete actions
    /// so the button itself is red even before the dialog opens.</summary>
    [Parameter] public Button.ButtonVariant Variant { get; set; } = Button.ButtonVariant.Default;

    /// <summary>Size of the trigger button.</summary>
    [Parameter] public Button.ButtonSize Size { get; set; } = Button.ButtonSize.Default;

    /// <summary>Disables the trigger button, preventing the confirm dialog from opening.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Shows the trigger button's loading state (spinner, disabled interaction)
    /// while the caller has a pending operation in flight — forwarded to <see cref="Button"/>.</summary>
    [Parameter] public bool IsLoading { get; set; }

    /// <summary>Additional CSS classes merged onto the trigger button.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes splatted onto the trigger button.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Re-entrancy guard: a fast double-click (or Enter-then-click) would
    // otherwise open a second confirm dialog on top of the first AND fire
    // OnConfirm twice. We gate on the in-flight flag so only one dialog can be
    // open per trigger at a time; it's reset in a finally so a throwing
    // OnConfirm handler can't wedge the button permanently shut.
    private bool _inFlight;

    // Lifecycle guard (#29): the confirm dialog is awaited across a yield, during
    // which the parent can remove this ConfirmButton from the tree. Without a
    // teardown guard the destructive OnConfirm/OnCancel would still fire against a
    // disposed component once the user resolves an orphaned dialog. We record the
    // active overlay's id so Dispose can tear the dialog down, and short-circuit
    // the post-await callbacks once disposed.
    private bool _disposed;
    private string? _activeOverlayId;

    private async Task HandleClick()
    {
        if (_inFlight || _disposed) return;
        _inFlight = true;

        // Capture the id of the overlay this click is about to open so Dispose
        // can cancel exactly our dialog (and nobody else's). OnShow fires
        // synchronously from ShowAlertDialogAsync, so a one-shot subscription
        // around the call grabs the right instance without racing.
        void Capture(Lumeo.Services.OverlayInstance instance) => _activeOverlayId = instance.Id;

        try
        {
            var opts = new Lumeo.Services.AlertDialogOptions
            {
                Title = Title ?? L["ConfirmButton.Title"],
                Description = Description,
                ConfirmText = ConfirmText ?? L["ConfirmButton.Confirm"],
                CancelText = CancelText ?? L["ConfirmButton.Cancel"],
                IsDestructive = IsDestructive,
            };

            Overlay.OnShow += Capture;
            Task<Lumeo.Services.OverlayResult> pending;
            try
            {
                pending = Overlay.ShowAlertDialogAsync(opts);
            }
            finally
            {
                Overlay.OnShow -= Capture;
            }

            var result = await pending;

            // The component may have been disposed while the dialog was open. Do
            // NOT fire the destructive callback against a torn-down component.
            if (_disposed) return;

            if (result.Cancelled)
            {
                if (OnCancel.HasDelegate) await OnCancel.InvokeAsync();
            }
            else
            {
                if (OnConfirm.HasDelegate) await OnConfirm.InvokeAsync();
            }
        }
        finally
        {
            _activeOverlayId = null;
            _inFlight = false;
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        // Tear down an in-flight confirm dialog so an orphaned popup can't linger
        // after its owning button is gone. The OverlayProvider closes the dialog
        // and resolves its pending Task in response; even if the dialog still
        // resolves "confirmed", the _disposed guard above stops HandleClick from
        // firing OnConfirm against this torn-down component.
        if (_activeOverlayId is { } id)
        {
            _activeOverlayId = null;
            Overlay.Cancel(id);
        }
    }
}
